const v09ReadA={id:"v09-read-a",kind:"passage",label:"Passage for Items 69-72",title:"Cooling a Public Market",description:"Vendors in a covered public market reported intense afternoon heat. The city first installed two large fans near the main entrance, but temperature readings changed little in the rear aisles. A second trial paired roof vents with reflective panels above the hottest section. Sensors recorded lower peak temperatures there, while stalls outside the modified section showed little change. Because the trial covered only one month of the dry season, engineers recommended monitoring through the humid months before expanding the design.",alt:"Passage about a market-cooling trial in which entrance fans had little rear-aisle effect, roof vents and reflective panels lowered temperatures in one section, and engineers requested humid-season monitoring before expansion."};
const v09ReadB={id:"v09-read-b",kind:"passage",label:"Babasahin para sa Aytem 73-76",title:"Hiram na Kagamitang Pantanim",description:"Nagpahiram ang munisipyo ng mga pambungkal at pandilig sa mga samahang panghalaman. Dati, pangalan lamang ng humihiram ang isinusulat kaya mahirap matukoy kung kailan dapat ibalik ang kagamitan. Gumawa ang tagapangasiwa ng kard na may numero ng kagamitan, petsa ng hiram, takdang balik, at lagda ng tumanggap. Bumilis ang pagsubaybay, ngunit may ilang gamit na naibalik nang sira nang walang paliwanag. Idinagdag sa kard ang maikling tala ng kondisyon bago ilabas at pagkabalik. Sa sumunod na dalawang buwan, mas mabilis na natukoy kung kailan at kanino nangyari ang pinsala.",alt:"Teksto tungkol sa pagpapahiram ng kagamitang pantanim na gumamit ng may numerong kard, takdang balik, lagda, at tala ng kondisyon upang mapahusay ang pagsubaybay at pananagutan sa pinsala."};
const v09ReadC={id:"v09-read-c",kind:"passage",label:"Passage for Items 77-80",title:"Quiet-Zone Trial",description:"A licensing office created a quiet zone for applicants completing complicated forms. The zone had desks, sample forms, and written instructions, while routine inquiries remained at the information counter. Form corrections decreased, but staff noticed that first-time applicants still left the quiet zone to ask where certain supporting documents could be obtained. The office added a one-page directory of issuing agencies and tested it for three weeks. Corrections continued to fall, and fewer applicants interrupted the service counters, though the office retained staff assistance for people who had difficulty reading the guide.",alt:"Passage about a licensing-office quiet zone that reduced form corrections, then added an agency directory to answer supporting-document questions while retaining staff assistance for readers who needed help."};
const v09DataA={id:"v09-data-a",kind:"table",label:"Table for Items 155-158",title:"Community Water-Testing Samples",description:"Water samples scheduled, collected, and passing initial quality screening in four zones. Unit: samples.",headers:["Zone","Scheduled","Collected","Passed screening"],rows:[["Riverside",72,68,61],["Central",64,64,58],["Upland",80,72,63],["Coastal",60,57,51]],legend:["Collected: scheduled samples successfully obtained","Passed: collected samples meeting initial screening limits"],alt:"Table in samples. Riverside: 72 scheduled, 68 collected, 61 passed. Central: 64, 64, 58. Upland: 80, 72, 63. Coastal: 60, 57, 51."};
const v09DataB={id:"v09-data-b",kind:"bar-table",label:"Chart for Items 159-162",title:"Weekly Document Requests",description:"Grouped bar chart with exact table alternative. New and completed document requests by week. Unit: requests.",headers:["Week","New requests","Completed requests"],rows:[["Week 1",210,180],["Week 2",195,205],["Week 3",230,220],["Week 4",205,235]],legend:["Blue bars: New requests","Green bars: Completed requests"],alt:"Grouped bars in requests. Week 1: 210 new and 180 completed. Week 2: 195 and 205. Week 3: 230 and 220. Week 4: 205 and 235."};
const v09DataC={id:"v09-data-c",kind:"line-table",label:"Graph for Items 163-166",title:"Average Bus Delay by Time Period",description:"Line graph with exact table alternative. Average delay in minutes on five survey days for morning and evening service.",headers:["Day","Morning delay (minutes)","Evening delay (minutes)"],rows:[["Monday",8,14],["Tuesday",6,10],["Wednesday",9,12],["Thursday",5,9],["Friday",11,16]],legend:["Cyan line: Morning delay","Amber line: Evening delay"],alt:"Line data in minutes. Monday morning 8 and evening 14. Tuesday 6 and 10. Wednesday 9 and 12. Thursday 5 and 9. Friday 11 and 16."};
const v09DataD={id:"v09-data-d",kind:"table",label:"Table for Items 167-170",title:"Training Room Reservations",description:"Number of sessions, average participants per session, and cancellation count for four rooms during one month. Units: sessions and participants.",headers:["Room","Scheduled sessions","Average participants per held session","Cancelled sessions"],rows:[["Orchid",18,24,2],["Narra",20,18,1],["Molave",16,30,4],["Acacia",22,20,2]],legend:["Held sessions equal scheduled sessions minus cancelled sessions","Participant estimates use held sessions only"],alt:"Table. Orchid: 18 scheduled, average 24 participants per held session, 2 cancelled. Narra: 20, 18, 1. Molave: 16, 30, 4. Acacia: 22, 20, 2."};
